def numIslands(g):
    if not g: return 0
    m,n,cnt = len(g),len(g[0]),0
    def d(r,c):
        if r<0 or r>=m or c<0 or c>=n or g[r][c]=='0': return
        g[r][c]='0'; d(r+1,c); d(r-1,c); d(r,c+1); d(r,c-1)
    for r in range(m):
        for c in range(n):
            if g[r][c]=='1': cnt+=1; d(r,c)
    return cnt

